Resource: aws_sfn_state_machine.orders_orchestrator
File: /09_async_orders.tf: 69-106
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-logging-policies/bc-aws-284

		69  | resource "aws_sfn_state_machine" "orders_orchestrator" {
		70  |   name     = "${var.project_name}-orders-orchestrator"
		71  |   role_arn = aws_iam_role.step_functions_role.arn
		72  | 
		73  |   definition = jsonencode({
		74  |     Comment = "Orquesta verificación de stock, confirmación de compra y envío de email"
		75  |     StartAt = "VerificarStock"
		76  |     States = {
		77  |       VerificarStock = {
		78  |         Type     = "Task"
		79  |         Resource = aws_lambda_function.async["stock_check"].arn
		80  |         Next     = "ConfirmarCompra"
		81  |         Retry = [{
		82  |           ErrorEquals     = ["States.ALL"]
		83  |           MaxAttempts     = 3
		84  |           IntervalSeconds = 2
		85  |           BackoffRate     = 2.0
		86  |         }]
		87  |       }
		88  |       ConfirmarCompra = {
		89  |         Type     = "Task"
		90  |         Resource = aws_lambda_function.async["purchase_confirmation"].arn
		91  |         Next     = "EnviarEmail"
		92  |       }
		93  |       EnviarEmail = {
		94  |         Type     = "Task"
		95  |         Resource = aws_lambda_function.async["send_order_email"].arn
		96  |         End      = true
		97  |       }
		98  |     }
		99  |   })
		100 | 
		101 |   logging_configuration {
		102 |     log_destination        = "${aws_cloudwatch_log_group.sfn_logs.arn}:*"
		103 |     include_execution_data = true
		104 |     level                   = "ALL"
		105 |   }
		106 | }

